#include <bits/stdc++.h>
using namespace std;
int main(){
    int q;
    cin>>q;
    while(q--){
        int n,a[100005],b[100005];
        cin>>n;
        for(int i=1;i<=n;i++)
            cin>>a[i];
        for(int i=1;i<=n;i++)
            cin>>b[i];
        int i=1,j=1;
        bool flag=true;
        stack<int> s;
        while(j<=n){
            if(!s.empty() && s.top()==b[j]){
                s.pop(),j++;continue;
            }
            while(a[i]!=b[j] && i<=n)s.push(a[i++]);
            if(i>n){
                flag=false;
                break;
            }else i++,j++;
        }
        if(!flag)
            cout<<"No\n";
        else
            cout<<"Yes\n";
    }
    return 0;
}
